def setup_doc(doc):
    """Áp dụng VJES format: TNR 12, before/after 3pt, line 1.1, margins."""
    for sec in doc.sections:
        sec.top_margin = Cm(2.0); sec.bottom_margin = Cm(2.0)
        sec.left_margin = Cm(2.5); sec.right_margin = Cm(2.0)
    st = doc.styles['Normal']
    st.font.name = 'Times New Roman'
    st.font.size = Pt(12)
    st.paragraph_format.space_before = Pt(3)
    st.paragraph_format.space_after = Pt(3)
    st.paragraph_format.line_spacing = 1.1
    rpr = st.element.rPr or OxmlElement('w:rPr')
    rfonts = rpr.find(qn('w:rFonts')) or OxmlElement('w:rFonts')
    rfonts.set(qn('w:eastAsia'), 'Times New Roman')
    rpr.append(rfonts)


def make_paragraph(doc, text, *, bold=False, italic=False, size=12, align=None):
    p = doc.add_paragraph()
    if align: p.alignment = align
    r = p.add_run(text)
    r.font.name = 'Times New Roman'; r.font.size = Pt(size)
    r.bold = bold; r.italic = italic
    return p


